"from sqlalchemy import create_engine; from sqlalchemy.orm import sessionmaker; from sqlalchemy import text; engine = create_engine('postgresql://postgres@localhost:5432'); Session = sessionmaker(bind=engine); session = Session(); conn = engine.connect(); result = conn.execute(text('SELECT data_type FROM information_schema.columns WHERE table_name = \'documents\' AND column_name = \'embedding_status\';')); print('Data type:', result.fetchone()[0] if result else 'VARCHAR(20)')" 
